import { describe, expect, it } from "vitest";
import {
  isTerminalKeyEventTarget,
  shouldAppHandleKeybinding,
} from "./appKeybindingPolicy";

describe("appKeybindingPolicy", () => {
  it("lets focused xterm DOM receive keydown before app keybindings", () => {
    const terminal = document.createElement("div");
    terminal.className = "xterm";
    const textarea = document.createElement("textarea");
    textarea.className = "xterm-helper-textarea";
    terminal.append(textarea);

    expect(isTerminalKeyEventTarget(textarea)).toBe(true);
    expect(shouldAppHandleKeybinding(keydownFor(textarea, "Enter"))).toBe(false);
  });

  it("supports explicit terminal input markers outside xterm internals", () => {
    const customInput = document.createElement("div");
    customInput.dataset.kerminalTerminalInput = "true";

    expect(isTerminalKeyEventTarget(customInput)).toBe(true);
    expect(shouldAppHandleKeybinding(keydownFor(customInput, "j"))).toBe(false);
  });

  it("keeps non-terminal app surfaces eligible for global keybindings", () => {
    const settingsInput = document.createElement("input");

    expect(isTerminalKeyEventTarget(settingsInput)).toBe(false);
    expect(shouldAppHandleKeybinding(keydownFor(settingsInput, "s"))).toBe(true);
  });

  it("does not handle events that another layer already consumed", () => {
    const button = document.createElement("button");
    const event = keydownFor(button, "s");
    event.preventDefault();

    expect(shouldAppHandleKeybinding(event)).toBe(false);
  });
});

function keydownFor(target: Element, key: string) {
  const event = new KeyboardEvent("keydown", {
    bubbles: true,
    cancelable: true,
    key,
  });
  Object.defineProperty(event, "target", {
    configurable: true,
    value: target,
  });
  return event;
}

const TERMINAL_KEY_EVENT_TARGET_SELECTOR =
  "[data-kerminal-terminal-input], .xterm, .xterm-helper-textarea, .xterm-screen";

export function shouldAppHandleKeybinding(event: KeyboardEvent) {
  if (event.defaultPrevented) {
    return false;
  }

  return !isTerminalKeyEventTarget(event.target);
}

export function isTerminalKeyEventTarget(target: EventTarget | null) {
  const element = eventTargetElement(target);
  if (!element) {
    return false;
  }

  return Boolean(element.closest(TERMINAL_KEY_EVENT_TARGET_SELECTOR));
}

function eventTargetElement(target: EventTarget | null) {
  if (typeof Element !== "undefined" && target instanceof Element) {
    return target;
  }
  if (typeof Node !== "undefined" && target instanceof Node) {
    return target.parentElement;
  }
  return null;
}

import { fireEvent, render, screen, waitFor } from "@testing-library/react";
import { describe, expect, it, vi } from "vitest";
import { defaultAppSettings } from "../settings/settingsModel";
import { mocks } from "./__tests__/support/XtermPane.testSupport";
import { XtermPane } from "./XtermPane";

describe("XtermPane input compatibility", () => {
  it("maps Agent TUI Shift+Enter to LF without xterm default CR", async () => {
    render(
      <XtermPane
        focused
        inputCompatibilityMode="agentTui"
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });

    const result = mocks.terminalInstances[0].triggerCustomKeyEvent({
      code: "Enter",
      key: "Enter",
      keyCode: 13,
      shiftKey: true,
    });

    expect(result).toEqual({ defaultPrevented: true, result: false });
    expect(mocks.api.writeTerminal).toHaveBeenCalledWith("session-1", "\n");
    expect(mocks.api.writeTerminal).not.toHaveBeenCalledWith("session-1", "\r");
  });

  it("does not intercept Agent TUI Shift+Enter during IME composition", async () => {
    render(
      <XtermPane
        focused
        inputCompatibilityMode="agentTui"
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });

    const result = mocks.terminalInstances[0].triggerCustomKeyEvent({
      code: "Enter",
      isComposing: true,
      key: "Enter",
      keyCode: 13,
      shiftKey: true,
    });

    expect(result).toEqual({ defaultPrevented: false, result: true });
    expect(mocks.api.writeTerminal).not.toHaveBeenCalledWith("session-1", "\n");
  });

  it("leaves Shift+Enter on the xterm default path in shell mode", async () => {
    render(
      <XtermPane
        focused
        paneId="pane-shell"
        resolvedTheme="dark"
        terminalAppearance={defaultAppSettings.terminal}
        title="PowerShell"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });

    const result = mocks.terminalInstances[0].triggerCustomKeyEvent({
      code: "Enter",
      key: "Enter",
      keyCode: 13,
      shiftKey: true,
    });

    expect(result).toEqual({ defaultPrevented: false, result: true });
    expect(mocks.api.writeTerminal).not.toHaveBeenCalledWith("session-1", "\n");
  });

  it("routes paste shortcuts through terminal paste instead of raw control bytes", async () => {
    const longPaste = [
      "first line",
      "第二行 with unicode",
      "last line " + "x".repeat(2048),
    ].join("\n");
    mocks.api.readTerminalClipboardText.mockResolvedValue(longPaste);
    render(
      <XtermPane
        focused
        inputCompatibilityMode="agentTui"
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });

    const terminal = mocks.terminalInstances[0];
    const ctrlV = terminal.triggerCustomKeyEvent({
      code: "KeyV",
      ctrlKey: true,
      key: "v",
      keyCode: 86,
    });
    const shiftInsert = terminal.triggerCustomKeyEvent({
      code: "Insert",
      key: "Insert",
      keyCode: 45,
      shiftKey: true,
    });

    expect(ctrlV).toEqual({ defaultPrevented: true, result: false });
    expect(shiftInsert).toEqual({ defaultPrevented: true, result: false });
    await waitFor(() => {
      expect(terminal.paste).toHaveBeenCalledTimes(2);
    });
    expect(terminal.paste).toHaveBeenCalledWith(longPaste);
    expect(mocks.api.writeTerminal).not.toHaveBeenCalledWith("session-1", "\x16");
  });

  it("reports fitted terminal dimensions to callers", async () => {
    const onTerminalDimensionsChange = vi.fn();

    render(
      <XtermPane
        focused
        onTerminalDimensionsChange={onTerminalDimensionsChange}
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });

    await waitFor(() => {
      expect(onTerminalDimensionsChange).toHaveBeenCalledWith({
        cols: 100,
        rows: 30,
      });
    });
    expect(mocks.api.resizeTerminal).toHaveBeenCalledWith("session-1", {
      cols: 100,
      rows: 30,
    });
  });

  it("focuses the terminal from focus requests and terminal-area pointer input", async () => {
    const { rerender } = render(
      <XtermPane
        focused={false}
        focusRequestToken={0}
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });
    const terminal = mocks.terminalInstances[0];
    terminal.focus.mockClear();

    rerender(
      <XtermPane
        focused={false}
        focusRequestToken={1}
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    expect(terminal.focus).toHaveBeenCalledTimes(1);
    terminal.focus.mockClear();

    fireEvent.pointerDown(screen.getByLabelText("Codex xterm 终端"));

    expect(terminal.focus).toHaveBeenCalledTimes(1);
  });

  it("pastes external Agent composer requests through xterm and optionally submits", async () => {
    const { rerender } = render(
      <XtermPane
        focused
        inputRequest={null}
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    await waitFor(() => {
      expect(screen.getByText("已连接")).toBeInTheDocument();
    });
    const terminal = mocks.terminalInstances[0];
    terminal.paste.mockClear();
    terminal.focus.mockClear();
    mocks.api.writeTerminal.mockClear();

    rerender(
      <XtermPane
        focused
        inputRequest={{ id: "paste-1", text: "line1\nline2" }}
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    expect(terminal.paste).toHaveBeenCalledWith("line1\nline2");
    expect(mocks.api.writeTerminal).not.toHaveBeenCalledWith("session-1", "\r");
    expect(terminal.focus).toHaveBeenCalledTimes(1);

    rerender(
      <XtermPane
        focused
        inputRequest={{ id: "submit-1", submit: true, text: "run tests" }}
        paneId="pane-agent-codex"
        resolvedTheme="dark"
        shellAssistEnabled={false}
        terminalAppearance={defaultAppSettings.terminal}
        title="Codex"
      />,
    );

    expect(terminal.paste).toHaveBeenLastCalledWith("run tests");
    expect(mocks.api.writeTerminal).toHaveBeenCalledWith("session-1", "\r");
  });
});

import { afterEach, describe, expect, it, vi } from "vitest";

describe("real xterm compatibility", () => {
  afterEach(() => {
    vi.restoreAllMocks();
    document.body.innerHTML = "";
  });

  it("wraps exact long paste content when bracketed paste is enabled", async () => {
    const harness = await createRealXtermHarness();
    const longPaste = [
      "first line",
      "第二行 with unicode",
      "last line " + "x".repeat(2048),
    ].join("\n");

    try {
      await harness.write("\x1b[?2004h");
      harness.terminal.paste(longPaste);

      const normalizedPaste = longPaste.replace(/\n/g, "\r");
      expect(harness.data.join("")).toBe(
        `\x1b[200~${normalizedPaste}\x1b[201~`,
      );
    } finally {
      harness.dispose();
    }
  });

  it("tracks alternate screen enter and exit without losing the normal buffer", async () => {
    const harness = await createRealXtermHarness();

    try {
      await harness.write("normal buffer\r\n");
      expect(harness.terminal.buffer.active.type).toBe("normal");

      await harness.write("\x1b[?1049h");
      expect(harness.terminal.buffer.active.type).toBe("alternate");

      await harness.write("\x1b[?1049l");
      expect(harness.terminal.buffer.active.type).toBe("normal");
      expect(
        harness.terminal.buffer.normal.getLine(0)?.translateToString(true),
      ).toContain("normal buffer");
    } finally {
      harness.dispose();
    }
  });

  it("emits SGR mouse reports when terminal mouse tracking is enabled", async () => {
    const harness = await createRealXtermHarness();
    const terminalElement = harness.container.querySelector(".xterm");
    const screenElement = harness.container.querySelector(".xterm-screen");

    expect(terminalElement).toBeInstanceOf(HTMLElement);
    expect(screenElement).toBeInstanceOf(HTMLElement);

    try {
      stubElementRect(screenElement as HTMLElement, {
        height: 480,
        left: 10,
        top: 20,
        width: 800,
      });
      await harness.write("\x1b[?1000h\x1b[?1006h");

      terminalElement?.dispatchEvent(
        new MouseEvent("mousedown", {
          bubbles: true,
          button: 0,
          buttons: 1,
          cancelable: true,
          clientX: 25,
          clientY: 35,
        }),
      );
      document.dispatchEvent(
        new MouseEvent("mouseup", {
          bubbles: true,
          button: 0,
          buttons: 0,
          cancelable: true,
          clientX: 25,
          clientY: 35,
        }),
      );

      const rawData = harness.data.join("");
      expect(rawData).toMatch(/\x1b\[<0;\d+;\d+M/);
      expect(rawData).toMatch(/\x1b\[<0;\d+;\d+m/);
    } finally {
      harness.dispose();
    }
  });

  it("emits resize events and keeps normal scrollback bounded", async () => {
    const harness = await createRealXtermHarness({ rows: 2, scrollback: 3 });
    const resizeEvents: Array<{ cols: number; rows: number }> = [];
    const disposable = harness.terminal.onResize((event) =>
      resizeEvents.push(event),
    );

    try {
      harness.terminal.resize(100, 30);
      expect(resizeEvents).toContainEqual(
        expect.objectContaining({ cols: 100, rows: 30 }),
      );

      await harness.write("one\r\ntwo\r\nthree\r\nfour\r\nfive\r\nsix\r\n");
      expect(harness.terminal.buffer.normal.length).toBeLessThanOrEqual(
        harness.terminal.rows + 3,
      );
    } finally {
      disposable.dispose();
      harness.dispose();
    }
  });
});

async function createRealXtermHarness(options?: {
  rows?: number;
  scrollback?: number;
}) {
  installBrowserApiStubs();

  const { Terminal: XtermTerminal } = await import("@xterm/xterm");
  const container = document.createElement("div");
  document.body.appendChild(container);
  const terminal = new XtermTerminal({
    cols: 80,
    rows: options?.rows ?? 24,
    scrollback: options?.scrollback ?? 1000,
  });
  const data: string[] = [];
  terminal.onData((entry) => data.push(entry));
  terminal.open(container);

  return {
    container,
    data,
    dispose() {
      terminal.dispose();
      container.remove();
    },
    terminal,
    write(entry: string) {
      return new Promise<void>((resolve) => terminal.write(entry, resolve));
    },
  };
}

function stubElementRect(
  element: HTMLElement,
  rect: Pick<DOMRect, "height" | "left" | "top" | "width">,
) {
  element.style.paddingLeft = "0px";
  element.style.paddingTop = "0px";
  element.getBoundingClientRect = () =>
    ({
      bottom: rect.top + rect.height,
      height: rect.height,
      left: rect.left,
      right: rect.left + rect.width,
      top: rect.top,
      width: rect.width,
      x: rect.left,
      y: rect.top,
      toJSON: () => ({}),
    }) as DOMRect;
}

function installBrowserApiStubs() {
  Object.defineProperty(window, "matchMedia", {
    configurable: true,
    value: () => ({
      addEventListener: vi.fn(),
      addListener: vi.fn(),
      dispatchEvent: vi.fn(() => false),
      matches: false,
      media: "",
      onchange: null,
      removeEventListener: vi.fn(),
      removeListener: vi.fn(),
    }),
  });
  Object.defineProperty(window, "ResizeObserver", {
    configurable: true,
    value: class ResizeObserver {
      disconnect() {}
      observe() {}
      unobserve() {}
    },
  });
  Object.defineProperty(globalThis, "ResizeObserver", {
    configurable: true,
    value: window.ResizeObserver,
  });

  vi.spyOn(HTMLCanvasElement.prototype, "getContext").mockReturnValue(
    createCanvasContextStub() as unknown as CanvasRenderingContext2D,
  );
  vi.spyOn(HTMLElement.prototype, "offsetWidth", "get").mockReturnValue(320);
  vi.spyOn(HTMLElement.prototype, "offsetHeight", "get").mockReturnValue(16);
}

function createCanvasContextStub() {
  return {
    beginPath: vi.fn(),
    clearRect: vi.fn(),
    clip: vi.fn(),
    closePath: vi.fn(),
    createLinearGradient: vi.fn(() => ({ addColorStop: vi.fn() })),
    drawImage: vi.fn(),
    fillRect: vi.fn(),
    fillText: vi.fn(),
    getImageData: vi.fn(() => ({ data: new Uint8ClampedArray(4) })),
    measureText: vi.fn(() => ({ width: 10 })),
    putImageData: vi.fn(),
    rect: vi.fn(),
    restore: vi.fn(),
    save: vi.fn(),
    scale: vi.fn(),
    setTransform: vi.fn(),
    strokeRect: vi.fn(),
    strokeText: vi.fn(),
    translate: vi.fn(),
  };
}

import { afterEach, describe, expect, it, vi } from "vitest";
import {
  TERMINAL_KEYBOARD_COMPATIBILITY_CASES,
  describeTerminalKeyboardData,
  findTerminalKeyboardCompatibilityCase,
  resolveTerminalInputCompatibilityOverride,
  shouldAppKeybindingYieldForTerminalFocus,
  type TerminalKeyboardCompatibilityCase,
} from "./terminalKeyboardPolicy";

describe("terminalKeyboardPolicy", () => {
  afterEach(() => {
    vi.restoreAllMocks();
    document.body.innerHTML = "";
  });

  it("defines the production Agent terminal compatibility matrix", () => {
    expect(TERMINAL_KEYBOARD_COMPATIBILITY_CASES.map((entry) => entry.id)).toEqual(
      [
        "enter",
        "shiftEnter",
        "ctrlJ",
        "tab",
        "shiftTab",
        "escape",
        "ctrlC",
        "altEnter",
        "ctrlV",
        "shiftInsert",
      ],
    );
  });

  it("documents the xterm 6 Shift+Enter collision and Agent TUI target", () => {
    const enter = caseById("enter");
    const shiftEnter = caseById("shiftEnter");

    expect(describeTerminalKeyboardData(enter.xterm6DefaultData)).toBe("CR");
    expect(describeTerminalKeyboardData(shiftEnter.xterm6DefaultData)).toBe("CR");
    expect(describeTerminalKeyboardData(shiftEnter.agentTuiTargetData)).toBe(
      "LF",
    );
  });

  it("marks terminal focused Agent TUI keys as app keybinding yield points", () => {
    for (const entry of TERMINAL_KEYBOARD_COMPATIBILITY_CASES) {
      expect(findTerminalKeyboardCompatibilityCase(entry.event)?.id).toBe(
        entry.id,
      );
      expect(shouldAppKeybindingYieldForTerminalFocus(entry.event)).toBe(true);
    }

    expect(
      shouldAppKeybindingYieldForTerminalFocus({
        code: "KeyS",
        ctrlKey: true,
        key: "s",
        keyCode: 83,
      }),
    ).toBe(false);
  });

  it("overrides only Agent TUI Shift+Enter to LF", () => {
    expect(
      resolveTerminalInputCompatibilityOverride(caseById("shiftEnter").event, "agentTui"),
    ).toEqual({ data: "\n" });
    expect(
      resolveTerminalInputCompatibilityOverride(caseById("enter").event, "agentTui"),
    ).toBeNull();
    expect(
      resolveTerminalInputCompatibilityOverride(caseById("shiftEnter").event, "shell"),
    ).toBeNull();
  });

  it("does not override IME composition key events", () => {
    expect(
      resolveTerminalInputCompatibilityOverride(
        { ...caseById("shiftEnter").event, isComposing: true },
        "agentTui",
      ),
    ).toBeNull();
    expect(
      resolveTerminalInputCompatibilityOverride(
        { ...caseById("shiftEnter").event, keyCode: 229 },
        "agentTui",
      ),
    ).toBeNull();
  });

  it("records xterm 6 raw bytes with a fake PTY recorder", async () => {
    const harness = await createRealXtermKeyboardHarness();

    try {
      for (const entry of TERMINAL_KEYBOARD_COMPATIBILITY_CASES) {
        const result = harness.press(entry);

        expect(result.data, entry.label).toBe(entry.xterm6DefaultData ?? "");
        expect(result.defaultPrevented, entry.label).toBe(
          entry.defaultPreventedByXterm6,
        );
      }
    } finally {
      harness.dispose();
    }
  });
});

function caseById(id: TerminalKeyboardCompatibilityCase["id"]) {
  const entry = TERMINAL_KEYBOARD_COMPATIBILITY_CASES.find(
    (current) => current.id === id,
  );
  expect(entry).toBeDefined();
  return entry!;
}

async function createRealXtermKeyboardHarness() {
  installBrowserApiStubs();

  const { Terminal: XtermTerminal } = await import("@xterm/xterm");
  const container = document.createElement("div");
  document.body.appendChild(container);
  const terminal = new XtermTerminal({ cols: 80, rows: 24 });
  const ptyWrites: string[] = [];
  terminal.onData((data) => ptyWrites.push(data));
  terminal.open(container);
  terminal.focus();

  const textarea = container.querySelector<HTMLTextAreaElement>(
    ".xterm-helper-textarea",
  );
  expect(textarea).toBeInstanceOf(HTMLTextAreaElement);

  return {
    dispose() {
      terminal.dispose();
      container.remove();
    },
    press(entry: TerminalKeyboardCompatibilityCase) {
      ptyWrites.length = 0;
      const event = new KeyboardEvent("keydown", {
        altKey: Boolean(entry.event.altKey),
        bubbles: true,
        cancelable: true,
        code: entry.event.code,
        ctrlKey: Boolean(entry.event.ctrlKey),
        key: entry.event.key,
        keyCode: entry.event.keyCode,
        metaKey: Boolean(entry.event.metaKey),
        shiftKey: Boolean(entry.event.shiftKey),
        which: entry.event.keyCode,
      });

      textarea!.dispatchEvent(event);

      return {
        data: ptyWrites.join(""),
        defaultPrevented: event.defaultPrevented,
      };
    },
  };
}

function installBrowserApiStubs() {
  Object.defineProperty(window, "matchMedia", {
    configurable: true,
    value: () => ({
      addEventListener: vi.fn(),
      addListener: vi.fn(),
      dispatchEvent: vi.fn(() => false),
      matches: false,
      media: "",
      onchange: null,
      removeEventListener: vi.fn(),
      removeListener: vi.fn(),
    }),
  });
  Object.defineProperty(window, "ResizeObserver", {
    configurable: true,
    value: class ResizeObserver {
      disconnect() {}
      observe() {}
      unobserve() {}
    },
  });
  Object.defineProperty(globalThis, "ResizeObserver", {
    configurable: true,
    value: window.ResizeObserver,
  });

  vi.spyOn(HTMLCanvasElement.prototype, "getContext").mockReturnValue(
    createCanvasContextStub() as unknown as CanvasRenderingContext2D,
  );
}

function createCanvasContextStub() {
  return {
    beginPath: vi.fn(),
    clearRect: vi.fn(),
    clip: vi.fn(),
    closePath: vi.fn(),
    createLinearGradient: vi.fn(() => ({ addColorStop: vi.fn() })),
    drawImage: vi.fn(),
    fillRect: vi.fn(),
    fillText: vi.fn(),
    getImageData: vi.fn(() => ({ data: new Uint8ClampedArray(4) })),
    measureText: vi.fn(() => ({ width: 10 })),
    putImageData: vi.fn(),
    rect: vi.fn(),
    restore: vi.fn(),
    save: vi.fn(),
    scale: vi.fn(),
    setTransform: vi.fn(),
    strokeRect: vi.fn(),
    strokeText: vi.fn(),
    translate: vi.fn(),
  };
}

export type TerminalKeyboardCaseId =
  | "enter"
  | "shiftEnter"
  | "ctrlJ"
  | "tab"
  | "shiftTab"
  | "escape"
  | "ctrlC"
  | "altEnter"
  | "ctrlV"
  | "shiftInsert";

export type TerminalInputCompatibilityMode = "shell" | "agentTui";

export interface TerminalKeyboardEventDescriptor {
  altKey?: boolean;
  code: string;
  ctrlKey?: boolean;
  key: string;
  keyCode: number;
  metaKey?: boolean;
  shiftKey?: boolean;
}

export type TerminalKeyboardHandlingIntent = "sendData" | "nativePaste";

export interface TerminalKeyboardCompatibilityCase {
  agentTuiTargetData: string | null;
  defaultPreventedByXterm6: boolean;
  event: TerminalKeyboardEventDescriptor;
  handlingIntent: TerminalKeyboardHandlingIntent;
  id: TerminalKeyboardCaseId;
  label: string;
  xterm6DefaultData: string | null;
}

export const TERMINAL_KEYBOARD_COMPATIBILITY_CASES = [
  {
    agentTuiTargetData: "\r",
    defaultPreventedByXterm6: true,
    event: { code: "Enter", key: "Enter", keyCode: 13 },
    handlingIntent: "sendData",
    id: "enter",
    label: "Enter",
    xterm6DefaultData: "\r",
  },
  {
    agentTuiTargetData: "\n",
    defaultPreventedByXterm6: true,
    event: { code: "Enter", key: "Enter", keyCode: 13, shiftKey: true },
    handlingIntent: "sendData",
    id: "shiftEnter",
    label: "Shift+Enter",
    xterm6DefaultData: "\r",
  },
  {
    agentTuiTargetData: "\n",
    defaultPreventedByXterm6: true,
    event: { code: "KeyJ", ctrlKey: true, key: "j", keyCode: 74 },
